// extractTitleFromFilename strips the trailing extension for use as
// the prefilled issue title when the viewer picks "New issue from
// this attachment". An empty filename → empty title.
func extractTitleFromFilename(name string) string {
	if name == "" {
		return ""
	}
	for i := len(name) - 1; i >= 0; i-- {
		if name[i] == '.' {
			return name[:i]
		}
		if name[i] == '/' || name[i] == ' ' {
			break
		}
	}
	return name
}

